const fs = require\('fs'\);
const path = require\('path'\);

function getRgbaReplacement\(base, alphaStr\) {
  const alpha = parseFloat\(alphaStr\);
  const pct = Math.round\(alpha * 100\);
  return 'color-mix\(in srgb,var\(' + base + '\) ' + pct + '%,transparent\)';
}

const patterns = [
  [/rgba\\\(255,107,26,\([0-9.]+\)\\\)/g,    \(_, a\) => getRgbaReplacement\('--accent', a\)],
  [/rgba\\\(255, 107, 26, \([0-9.]+\)\\\)/g, \(_, a\) => getRgbaReplacement\('--accent', a\)],
  [/rgba\\\(255,140,66,\([0-9.]+\)\\\)/g,    \(_, a\) => getRgbaReplacement\('--accent-2', a\)],
  [/rgba\\\(255, 140, 66, \([0-9.]+\)\\\)/g, \(_, a\) => getRgbaReplacement\('--accent-2', a\)],
  [/#FF6B1A/g, 'var\(--accent\)'],
  [/#FF8C42/g, 'var\(--accent-2\)'],
];

function processDir\(dir\) {
  for \(const file of fs.readdirSync\(dir, {withFileTypes: true}\)\) {
    const full = path.join\(dir, file.name\);
    if \(file.isDirectory\(\)\) { processDir\(full\); continue; }
    if \(!/\\.\(vue|css\)$/.test\(file.name\)\) continue;
    let content = fs.readFileSync\(full, 'utf8'\);
    const orig = content;
    for \(const [pat, repl] of patterns\) {
      content = content.replace\(pat, repl\);
    }
    if \(content !== orig\) {
      fs.writeFileSync\(full, content, 'utf8'\);
      console.log\('Updated: ' + file.name\);
    }
  }
}

processDir\('C:/Users/thoma/Documents/HORNAX/src'\);
